// 1. The one-liner — 90% of records look like this
record Point(int x, int y) {}

// 2. With a compact constructor for validation (NO parameter list, NO field assignment — those are automatic)
record Range(int lo, int hi) {
  Range {
    if (lo > hi) throw new IllegalArgumentException("lo > hi");
  }
}

// 3. With extra static factory + instance methods
record Money(long amountCents, String currency) {
  static Money usd(long cents) { return new Money(cents, "USD"); }
  double toDollars() { return amountCents / 100.0; }
}

// 4. Implementing an interface
interface Named { String name(); }
record Person(String name, int age) implements Named {}

// 5. Overriding a generated accessor (defensive copy)
record Team(String name, List<String> members) {
  public List<String> members() {
    return List.copyOf(members);   // return an unmodifiable copy
  }
}

// File: RecordsDemo.java
// Run: javac RecordsDemo.java && java RecordsDemo
import java.util.*;

public class RecordsDemo {

  record Point(int x, int y) {}

  record Range(int lo, int hi) {
    Range {
      if (lo > hi) throw new IllegalArgumentException("lo > hi");
    }
    int size() { return hi - lo + 1; }
  }

  record Coord(int x, int y) {}

  public static void main(String[] args) {
    Point p1 = new Point(2, 3);
    Point p2 = new Point(2, 3);
    Point p3 = new Point(4, 5);

    // Value equality — different objects but equal by content
    System.out.println(p1 == p2);         // false
    System.out.println(p1.equals(p2));    // true
    System.out.println(p1.equals(p3));    // false

    // Auto toString
    System.out.println(p1);                // Point[x=2, y=3]

    // Accessors — NOTE: x() not getX()
    System.out.println(p1.x() + "," + p1.y());

    // Compact constructor validation
    try {
      new Range(5, 3);
    } catch (IllegalArgumentException e) {
      System.out.println("caught: " + e.getMessage());
    }
    System.out.println(new Range(1, 5).size());

    // Records shine as map keys — value semantics + immutable
    Map<Coord, String> grid = new HashMap<>();
    grid.put(new Coord(0, 0), "origin");
    grid.put(new Coord(1, 0), "east");
    System.out.println(grid.get(new Coord(0, 0)));   // origin
  }
}

// Output:
//   false
//   true
//   false
//   Point[x=2, y=3]
//   2,3
//   caught: lo > hi
//   5
//   origin

